"use client";

import { useAuth } from "@/lib/auth-context";
import { useData } from "@/lib/data-context";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import Link from "next/link";
import Image from "next/image";
import {
  FolderKanban,
  ListTodo,
  CheckCircle2,
  Clock,
  AlertTriangle,
  Plus,
  ArrowRight,
  Sparkles,
  ChevronRight,
} from "lucide-react";
import { format, isPast, parseISO } from "date-fns";

export default function DashboardPage() {
  const { user } = useAuth();
  const { projects, getMyTasks } = useData();

  const myTasks = getMyTasks();
  const completedTasks = myTasks.filter((t) => t.status === "done").length;
  const pendingTasks = myTasks.filter((t) => t.status !== "done").length;
  const overdueTasks = myTasks.filter(
    (t) => t.dueDate && isPast(parseISO(t.dueDate)) && t.status !== "done"
  ).length;

  const activeProjects = projects.filter((p) => p.status === "active").length;

  const stats = [
    { title: "Total Projects", value: projects.length, icon: FolderKanban, color: "text-blue-500", bgColor: "bg-blue-500/10" },
    { title: "Active Projects", value: activeProjects, icon: FolderKanban, color: "text-green-500", bgColor: "bg-green-500/10" },
    { title: "My Tasks", value: myTasks.length, icon: ListTodo, color: "text-purple-500", bgColor: "bg-purple-500/10" },
    { title: "Completed", value: completedTasks, icon: CheckCircle2, color: "text-emerald-500", bgColor: "bg-emerald-500/10" },
    { title: "Pending", value: pendingTasks, icon: Clock, color: "text-orange-500", bgColor: "bg-orange-500/10" },
    { title: "Overdue", value: overdueTasks, icon: AlertTriangle, color: "text-red-500", bgColor: "bg-red-500/10" },
  ];

  const recentTasks = myTasks
    .filter((t) => t.status !== "done")
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    .slice(0, 5);

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case "urgent": return "bg-red-500";
      case "high": return "bg-orange-500";
      case "medium": return "bg-yellow-500";
      default: return "bg-blue-500";
    }
  };

  return (
    <div className="space-y-8 pb-10">
      {/* Header Section */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Welcome back, {user?.firstName}!</h1>
          <p className="text-muted-foreground">
            Here&apos;s what&apos;s happening with your projects today.
          </p>
        </div>
        <Link href="/projects/new">
          <Button className="rounded-full px-6">
            <Plus className="mr-2 h-4 w-4" />
            New Project
          </Button>
        </Link>
      </div>

      {/* Stats Grid */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6">
        {stats.map((stat) => (
          <Card key={stat.title} className="border-none bg-white/50 backdrop-blur-sm shadow-sm">
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <div className={`rounded-lg p-2 ${stat.bgColor}`}>
                  <stat.icon className={`h-5 w-5 ${stat.color}`} />
                </div>
                <div>
                  <p className="text-2xl font-bold">{stat.value}</p>
                  <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">{stat.title}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Main Content Grid */}
      <div className="grid gap-6 lg:grid-cols-2">
        <Card className="border-none bg-white/60 shadow-md rounded-[2rem] overflow-hidden">
          <CardHeader className="flex flex-row items-center justify-between border-b border-black/5 bg-black/5 pb-4">
            <div>
              <CardTitle>Recent Projects</CardTitle>
              <CardDescription>Your active progress</CardDescription>
            </div>
            <Link href="/projects">
              <Button variant="ghost" size="sm" className="rounded-full">
                View All
              </Button>
            </Link>
          </CardHeader>
          <CardContent className="space-y-4 pt-6">
            {projects.slice(0, 3).map((project) => {
              const totalTasks = project.panels.reduce((sum, panel) => sum + panel.tasks.length, 0);
              const progress = totalTasks > 0 ? 65 : 0; // Simplified for UI example

              return (
                <Link key={project.id} href={`/projects/${project.id}`} className="block group">
                  <div className="flex items-center justify-between rounded-2xl border bg-white p-4 transition-all hover:shadow-md group-hover:border-primary/20">
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <h3 className="font-semibold">{project.name}</h3>
                        <Badge variant="secondary" className="text-[10px] uppercase">{project.status}</Badge>
                      </div>
                      <Progress value={progress} className="mt-3 h-1.5" />
                    </div>
                    <ArrowRight className="ml-4 h-4 w-4 text-muted-foreground transition-transform group-hover:translate-x-1" />
                  </div>
                </Link>
              );
            })}
          </CardContent>
        </Card>

        <Card className="border-none bg-white/60 shadow-md rounded-[2rem] overflow-hidden">
          <CardHeader className="flex flex-row items-center justify-between border-b border-black/5 bg-black/5 pb-4">
            <div>
              <CardTitle>My Tasks</CardTitle>
              <CardDescription>Personal queue</CardDescription>
            </div>
            <Link href="/tasks">
              <Button variant="ghost" size="sm" className="rounded-full">
                View All
              </Button>
            </Link>
          </CardHeader>
          <CardContent className="space-y-3 pt-6">
            {recentTasks.map((task) => (
              <div key={task.id} className="flex items-center gap-3 rounded-xl border bg-white p-3 shadow-sm">
                <div className={`h-2 w-2 rounded-full ${getPriorityColor(task.priority)}`} />
                <div className="flex-1 min-w-0">
                  <p className="font-medium truncate text-sm">{task.title}</p>
                </div>
                <Badge variant="outline" className="text-[10px] uppercase px-2">{task.priority}</Badge>
              </div>
            ))}
          </CardContent>
        </Card>
      </div>

      {/* EXTENSION: Design Preview Section (Matches Landing Page Style) */}
      <section className="mt-12">
        <div className="mb-6 flex items-center gap-2 text-xs font-bold uppercase tracking-[0.24em] text-[#8a8383]">
          <Sparkles className="h-4 w-4" />
          Workspace Interface Designs
        </div>
        
        <div className="grid gap-6 md:grid-cols-3">
          {[
            { src: "/design-1.png", title: "Global Tracker", desc: "AI-driven map view" },
            { src: "/design-2.png", title: "Task Flow", desc: "Intuitive kanban logic" },
            { src: "/design-3.png", title: "Premium Tools", desc: "Governance dashboard" }
          ].map((item, index) => (
            <div 
              key={index} 
              className="group relative flex flex-col rounded-[2.5rem] bg-[#e8e0e0]/95 p-3 shadow-[0_16px_45px_rgba(90,84,84,0.08)] transition-all hover:-translate-y-1 hover:shadow-xl"
            >
              <div className="relative aspect-[4/3] w-full overflow-hidden rounded-[2rem] bg-gray-200">
                <Image
                  src={item.src}
                  alt={item.title}
                  fill
                  className="object-cover transition-transform duration-500 group-hover:scale-110"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent opacity-0 transition-opacity group-hover:opacity-100" />
              </div>
              <div className="p-5">
                <div className="flex items-center justify-between">
                  <h3 className="text-lg font-black tracking-tighter text-[#6c6868] uppercase">
                    {item.title}
                  </h3>
                  <ChevronRight className="h-4 w-4 text-[#8a8383]" />
                </div>
                <p className="mt-1 text-sm font-medium text-[#383536]/70">
                  {item.desc}
                </p>
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}